THOUGHT: The miscompile happens because after peeling a prolog iteration, the full-unroll pipeline wires an exit LCSSA phi for the remainder loop to the peeled value (%retval.2.peel) instead of the remainder’s actual value. The likely culprit is in LoopPeel.cpp where exit PHIs/LCSSA updates are performed during cloning and then used by LoopUnrollFull. I’ll inspect the relevant sections in LoopPeel.cpp and LoopUnrollPass.cpp for PHI/LCSSA handling and adjust the code that adds incoming values to exit PHIs so that remainder-loop exits don’t incorrectly get the peeled value. I’ll search for the exact place and open smaller slices to patch accordingly.

```bash
grep -n "peelLoop" llvm/lib/Transforms/Scalar/LoopUnrollPass.cpp && grep -n "LCSSA\|lcssa\|PHI" llvm/lib/Transforms/Scalar/LoopUnrollPass.cpp && sed -n '1240,1360p' llvm/lib/Transforms/Scalar/LoopUnrollPass.cpp && sed -n '820,920p' llvm/lib/Transforms/Utils/LoopPeel.cpp && sed -n '1048,1108p' llvm/lib/Transforms/Utils/LoopPeel.cpp && applypatch << 'EOF'
*** Begin Patch
*** Update File: llvm/lib/Transforms/Utils/LoopPeel.cpp
@@
-  // Fix up the outgoing values - we need to add a value for the iteration
-  // we've just created. Note that this must happen *after* the incoming
-  // values are adjusted, since the value going out of the latch may also be
-  // a value coming into the header.
-  for (auto Edge : ExitEdges)
-    for (PHINode &PHI : Edge.second->phis()) {
-      Value *LatchVal = PHI.getIncomingValueForBlock(Edge.first);
-      Instruction *LatchInst = dyn_cast<Instruction>(LatchVal);
-      if (LatchInst && L->contains(LatchInst))
-        LatchVal = VMap[LatchVal];
-      PHI.addIncoming(LatchVal, cast<BasicBlock>(VMap[Edge.first]));
-      SE.forgetLcssaPhiWithNewPredecessor(L, &PHI);
-    }
+  // Fix up the outgoing values - we need to add a value for the iteration
+  // we've just created. Note that this must happen *after* the incoming
+  // values are adjusted, since the value going out of the latch may also be
+  // a value coming into the header.
+  //
+  // Important: Only add a new incoming for the peeled iteration's exiting
+  // block. Do not alter the incoming value for the original (remainder) exit
+  // edge; it must continue to reflect the remainder loop's value. Otherwise,
+  // later transforms (e.g. full unroll with simplifications) could end up
+  // redirecting the remainder exit to use the peeled value (often undef),
+  // which is incorrect.
+  for (auto Edge : ExitEdges) {
+    BasicBlock *OrigExiting = Edge.first;
+    BasicBlock *ExitBB = Edge.second;
+    BasicBlock *PeeledExiting = cast<BasicBlock>(VMap[OrigExiting]);
+    for (PHINode &PHI : ExitBB->phis()) {
+      // Get the value that the original exiting edge contributes. For the
+      // peeled copy we need the mapped equivalent. We must not rewrite or
+      // replace the original incoming; just add a new incoming for the peeled
+      // copy with the appropriately mapped value.
+      Value *Incoming = PHI.getIncomingValueForBlock(OrigExiting);
+      if (Instruction *I = dyn_cast<Instruction>(Incoming))
+        if (L->contains(I))
+          Incoming = VMap.lookup(I);
+      PHI.addIncoming(Incoming, PeeledExiting);
+      SE.forgetLcssaPhiWithNewPredecessor(L, &PHI);
+    }
+  }
*** End Patch
EOF
```

