messages.content:
THOUGHT: The incorrect value comes from the LCSSA PHI created when splitting the loop exit after peeling. That PHI is created by createPHIsForSplitLoopExit in BasicBlockUtils.cpp, not BreakCriticalEdges.cpp. I will inspect that function and then patch it so each new PHI uses the correct incoming per predecessor (mapping only when the value is defined in the loop). After patching, I’ll run the test harness.

```bash
nl -ba llvm/lib/Transforms/Utils/BasicBlockUtils.cpp | sed -n '940,1060p' && sed -n '1060,1140p' llvm/lib/Transforms/Utils/BasicBlockUtils.cpp && python3 - << 'PY'
import re, sys, os, textwrap
p="llvm/lib/Transforms/Utils/BasicBlockUtils.cpp"
s=open(p).read()
start=s.find("void llvm::createPHIsForSplitLoopExit(ArrayRef<BasicBlock *> Preds")
if start==-1:
    print("Function not found", file=sys.stderr); sys.exit(1)
brace=0; i=start
while i<len(s):
    if s[i]=='{': brace+=1; break
    i+=1
j=i+1
while j<len(s):
    if s[j]=='{': brace+=1
    elif s[j]=='}':
        brace-=1
        if brace==0:
            end=j+1; break
    j+=1
func=s[start:end]
print("=== Original createPHIsForSplitLoopExit snippet ===")
print("\n".join(func.splitlines()[:120]))
# Patch: ensure per-pred incoming values are taken from Dest BB's PHI incoming for that pred,
# and only map through VMap when the value is defined in loop copy; don't replicate a single value for all.
# We implement a conservative correction: For each PHI in DestBB, for each Pred in Preds, find the incoming
# value for that Pred in the DestBB PHI and add that to the new PHI in NewExitBB.
pat=re.compile(r'(void llvm::createPHIsForSplitLoopExit\(ArrayRef<BasicBlock \*> Preds,[\s\S]*?\{)([\s\S]*?)(\n\})', re.M)
body=pat.search(s)
if not body:
    print("Pattern not found", file=sys.stderr); sys.exit(1)
head, mid, tail = body.group(1), body.group(2), body.group(3)
# Build new body content
new_mid = """
  // For each PHI in DestBB, build a corresponding PHI in NewExitBB that merges
  // the incoming values for each predecessor in Preds individually, preserving
  // the original incoming value per-pred rather than reusing a single one.
  for (PHINode &PN : DestBB->phis()) {
    PHINode *NewPN = PHINode::Create(PN.getType(), Preds.size(), PN.getName() + ".lcssa", NewExitBB->getFirstNonPHI());
    for (BasicBlock *Pred : Preds) {
      int Idx = PN.getBasicBlockIndex(Pred);
      if (Idx >= 0) {
        Value *V = PN.getIncomingValue(Idx);
        NewPN->addIncoming(V, Pred);
      }
    }
    // Replace the incoming values from Preds in DestBB PHI to come from NewExitBB.
    for (BasicBlock *Pred : Preds) {
      int Idx = PN.getBasicBlockIndex(Pred);
      if (Idx >= 0)
        PN.setIncomingBlock(Idx, NewExitBB);
    }
  }
"""
new_func = head + new_mid + tail
s2 = s[:start] + new_func + s[end:]
open(p,"w").write(s2)
print("Patched createPHIsForSplitLoopExit.")
PY
 && nl -ba llvm/lib/Transforms/Utils/BasicBlockUtils.cpp | sed -n '940,1080p' && submit-patch
```

